package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LogTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_ACHTERSTAL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

@Slf4j
public class BerekenBvVervangingsInkomen extends AbstractBerekenBv {

    public BerekenBvVervangingsInkomen(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            if (BvTools.checkMonitorHeeftBv(rekenTijd, opdracht)) {
                berekenBvVervangingsInkomen(mainContext, opdracht, rekenTijd);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBvVervangingsInkomen(RekenContext mainContext, Opdracht opdracht, RekenTijd rekenTijd) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        log.debug(LogTools.toSimpleLog(opdracht));
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        if (rekenTijd.isAchterstal) {
            berekenBvPercentage(BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);
            berekenBvPercentage(BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);
            berekenBvPercentage(BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);
            berekenBvPercentage(BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);
            berekenBvPercentage(BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY, BELASTBAAR_ACHTERSTAL_KEY, loonElementen);
        } else {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
                Money voluntariaatDispo = bvVoluntariaat.bepaalDispo(opdrachtContext, loonElementen);
                berekenBvPercentage(BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY, BELASTBAAR_KEY, loonElementen, voluntariaatDispo);
                berekenBvPercentage(BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY, BELASTBAAR_KEY, loonElementen);
                berekenBvPercentage(BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY, BELASTBAAR_KEY, loonElementen);
                berekenBvPercentage(BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY, BELASTBAAR_KEY, loonElementen);
                berekenBvPercentage(BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY, BELASTBAAR_KEY, loonElementen);
            }
        }
        log.trace("opdrachtsElementen:{}", loonElementen);
    }

    private void berekenBvPercentage(RekenBvKey bvKey, RekenBbKey bbKey, Collection<LoonElement> loonElementen) {
        berekenBvPercentage(bvKey, bbKey, loonElementen, Money.ZERO);
    }

    private void berekenBvPercentage(RekenBvKey bvKey, RekenBbKey bbKey, Collection<LoonElement> loonElementen, Money voluntariaat) {
        log.debug("berekenBvPercentage(\"{}\")", bvKey);
        Money belastbaar = getBelastbaar(bvKey, bbKey, loonElementen);
        BigDecimal percentage = getPercentage(bvKey);
        Money bedrijfsvoorheffing = belastbaar.multiply(percentage).round(2);
        bedrijfsvoorheffing = bedrijfsvoorheffing.add(voluntariaat);
        log.debug("\"{}\":{};belastbaar:{}; percentage:{}", bvKey, bedrijfsvoorheffing, belastbaar, percentage);
        herverdeelBedrijfsvoorheffing(bvKey, bedrijfsvoorheffing, bbKey, belastbaar, loonElementen);
    }

    private BigDecimal getPercentage(RekenBvKey bvKey) {
        BigDecimal percentage = BigDecimal.ZERO;
        switch (bvKey) {
            case BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY:
            case BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY:
            case BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY:
            case BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY:
            case BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY:
            case BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY:
                percentage = fiscaleConstanten.getPercentageVervangingsInkomenZiekte().movePointLeft(2);
                break;
            case BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY:
            case BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY:
                percentage = fiscaleConstanten.getPercentageVervangingsInkomenPremie().movePointLeft(2);
                break;
            case BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY:
            case BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY:
                percentage = fiscaleConstanten.getPercentageTijdelijkeArbeidsOngeschiktheid().movePointLeft(2);
                break;
            default:
                //TODO throw rekenLogic Exception
                break;
        }
        return percentage;
    }
}
